//!/bin/aeon --profile=ts.object.v1

/# Comment Stress (r5 target forms) #/
aeon:header = {
  version = "2.1"
  mode = "transport"
  profile = "ts.object.v1"
}

//# line doc
/# block doc #/
a:int32 = 1 //? line hint
/? block hint ?/

//@ line annotation
/@ block annotation @/
b:int32 = 2

//{ line structure
/{ block structure }/

//[ line profile
/[ block profile ]/

//( line instructions
/( block instructions )/

// plain line comment
/* plain block comment */

list:list<int32> = [
  1 /# postfix element doc #/
  /# prefix element doc #/ 2
  3
]

mixed = ~ /? reference hint ?/ list[1]

/# block doc for container #/
emptyList:list<int32> = [ /# container fallback #/ ]

/? orphan eof

//# Inline separator literal boundary failures.
//# These cases document current lexer greediness and should fail until
//# separator literal boundary rules are redesigned.

badInline1 = [ ^0,0 , 0,1 ]
badInline2 = [ ^0,0,0,1 ]
badInline3 = [ ^300x250 ]

//# Separator-char collisions that should be rejected by future policy.
badSepType1:matrix[,][;] = ^1,2,3;4,5,6
badSepType2:set[,] = ^0,0,0,
